// ASHRAE HANDBOOK OF FUNDAMENTALS 1972, p100, Eqn 32
#include <algorithm>
double ep_moist_enthalpy(double tdb, double dw) {
    double w = std::max(dw, 1.0e-5);
    return std::round((1.00484e3 * tdb + w * (2.50094e6 + 1.85895e3 * tdb)) * 100.0) / 100.0;
}

